// Script Continued Below
function onSubmit() {
	//Type appropriate comment here, and begin script below
	// STRY0074663
	if (g_form.getActionName() == 'save_contact') {
		return saveContact();
	}
}

function saveContact() {
	var grUserInfo;
	var bHaveContact = false;

	var contactData =  {};
		contactData.userId = g_form.getValue('u_user_information');

		// note may want to check values against record when saving on server to keep from updating when nothing changed.
		contactData.ou_contact_row_id = g_form.getUniqueValue();
		contactData.u_contact_ou = g_form.getValue('u_contact_ou');
		contactData.first_name = g_form.getValue('u_user_information.first_name');
		contactData.last_name = g_form.getValue('u_user_information.last_name');
		contactData.title = g_form.getValue('u_user_information.title');
		contactData.email = g_form.getValue('u_user_information.email');
		contactData.mobile_phone = g_form.getValue('u_user_information.mobile_phone');
		contactData.phone = g_form.getValue('u_user_information.phone');
		contactData.u_contact_notes = g_form.getValue('u_tasker_contact.u_contact_notes');

		var ga = new GlideAjax("ClientOrganizationalScripts");
		ga.addParam('sysparm_name', 'saveContactInfo');
		ga.addParam('sysparam_contactData',JSON.stringify(contactData));
		ga.getXML(saveContactInfo, null);
		function saveContactInfo(response) {
			var answer = response.responseXML.documentElement.getAttribute("answer");
			//g_form.setValue("u_tasker_contact.u_contact_notes",answer);
			// answer will be the error message if it fails
			return answer;
		}
	}
